{
  "schema_name": "eywa_node_response",
  "schema_version": "v1",
  "orchestration_decision": "delegate",
  "decision_notes": "The problem is a complex optimization task involving spatial search, noise handling, and cost minimization. I am breaking it down into geometric modeling, probabilistic query optimization, and cost-benefit analysis.",
  "helpers": [
    {
      "label": "geometric_modeler",
      "instructions": "Represent the known polyomino shapes as sets of relative coordinates. Create a function that, given a set of candidate placements on a grid, calculates the intersection of these placements with potential probe locations to identify which cells are most likely to belong to an oil field."
    },
    {
      "label": "probabilistic_query_optimizer",
      "instructions": "Develop a strategy for handling noisy aggregate queries. Given a set of possible polyomino placements and a noisy signal representing the number of oil cells in a region, calculate the posterior probability of each placement configuration using a Bayesian approach."
    },
    {
      "label": "cost_minimization_analyst",
      "instructions": "Evaluate the trade-off between the cost of a direct drilling probe versus the cost of a noisy aggregate query. Determine an optimal stopping criterion where the expected reduction in uncertainty (information gain) no longer justifies the cost of further queries before making the final guess."
    }
  ],
  "synthesis_brief": "Combine the geometric intersection data with the Bayesian posterior probabilities to identify the most likely oil-containing cells. Use the cost-minimization analysis to decide when to stop querying and transition to the final guess phase to minimize total probing cost."
}

